import { MinPriorityQueue } from '@datastructures-js/priority-queue';

function solve(edges, online, k) {
    const n = online.length;
    const adj = new Array(n).fill().map(() => []);
    for (const [u, v, cost] of edges) {
        adj[u].push([v, cost]);
    }

    let maxScore = -1;
    const visited = new Array(n).fill(false);
    const heap = new MinPriorityQueue({ priority: (x) => x.minCost });
    heap.enqueue({ node: 0, totalCost: 0, minCost: Infinity });

    while (!heap.isEmpty()) {
        const { node, totalCost, minCost } = heap.dequeue().element;
        if (node === n - 1) {
            if (totalCost <= k) {
                maxScore = Math.max(maxScore, minCost);
            }
            continue;
        }
        if (visited[node]) continue;
        visited[node] = true;

        for (const [neighbor, cost] of adj[node]) {
            if (!online[neighbor] && neighbor !== n - 1) continue;
            const newTotalCost = totalCost + cost;
            if (newTotalCost > k) continue;
            const newMinCost = Math.min(minCost, cost);
            heap.enqueue({ node: neighbor, totalCost: newTotalCost, minCost: newMinCost });
        }
    }

    return maxScore === Infinity ? -1 : maxScore;
}

